#include <bits/stdc++.h>
using namespace std;
const int N=105;
int n,t,p,q,p1[N],c[N],dp[N][50005];
int main()
{
    cin>>t;
    while(t--)
    {
        cin>>n>>p>>q;
        for(int i=1;i<=n;i++) cin>>p1[i]>>c[i];
        memset(dp,0,sizeof(dp));
        for(int i=1;i<=n;i++)
        {
            for(int j=1;j<=q;j++)
            {
                dp[i][j]=dp[i-1][j];
                if(c[i]<=j) dp[i][j]=max(dp[i][j],dp[i-1][j-c[i]]+p1[i]);
            }
        }
        for(int i=1;i<=q;i++)
        {
            if(dp[n][i]>=p)
            {
                cout<<i<<'\n';
                break;
            }
            if(i==q) cout<<"-1\n";
        }
    }
    return 0;
}
